#include <bits/stdc++.h>
using namespace std;
const int N=502;
int n,m,a[N],s[N];
long long f[N];
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    sort(a+1,a+n+1);
    for(int i=1;i<=n;i++)
        s[i]=s[i-1]+a[i];
    memset(f,0x3f,sizeof(f));
    f[0]=0,a[0]=-2e9;
    for(int i=1;i<=n;i++)
        for(int j=0;j<i;j++)
            f[i]=min(f[i],f[j]+1LL*(i-j)*max(a[j]+m,a[i])-(s[i]-s[j]));
    printf("%d",f[n]);
    return 0;
}
